from TDStoreTools import StorageManager
import TDFunctions as TDF

class BitwigSelectExt:
	"""
	BitwigSelectExt description
	"""
	def __init__(self, ownerComp):
		#comps
		self.ownerComp = ownerComp
		self.CompType = 'Select'
		#ops
		self.selectCompCHOP = self.ownerComp.op('selectCompOut')
		self.constantCHOP = self.ownerComp.op('constant1')
		self.selectChannelCHOP = self.ownerComp.op('select1')
		#pars
		self.compTypePar = self.ownerComp.par.Bitwigcomptype

		# properties
		TDF.createProperty(self, 'BitwigCompScope', value=[], dependable=True,
						   readOnly=False)
		TDF.createProperty(self, 'SelectedComp', value=None, dependable=True,
						   readOnly=False)

		# attributes:
		self.compTypeInfo = {
			'All' : None,
			'Song' : 'Song',
			'Track' : 'Track',
			'LauncherClip' : 'LauncherClip',
			'ClipSlot'	: 'ClipSlot',
			'ProjectRemotes' : 'ProjectControlPage',
			'TrackRemotes' : 'TrackControlPage',
			'DeviceRemotes' : 'DeviceControlPage',
			'Note' : 'Note'
		}

		self.mainParentShortcut = None
		self.selectedParentShortcut = None
		self.scanComps()

		#self.resetSelectedOp()
		run("args[0].resetSelectedOp()", self, delayFrames = 1, delayRef = op.TDResources)
		return

	def resetSelectedOp(self):
		try:
			self.onSelectedCompChange(self.ownerComp.par.Selectedcomp.eval())
			self.ownerComp.cook(force = True)
		except:
			pass

	def scanComps(self):
		if self.TDBitwigComp:
			filterType = self.compTypeInfo[self.compTypePar.eval()]
			if filterType:
				self.BitwigCompScope =  [comp for comp in self.TDBitwigComp.TDBitwigComps if comp.CompType == filterType]
			else:
				self.BitwigCompScope = self.TDBitwigComp.TDBitwigComps

	@property
	def TDBitwigComp(self):
		try:
			return self.ownerComp.par.Tdbitwigcomp.eval()
		except:
			return None

	@property
	def CompRelativePaths(self):
		if self.TDBitwigComp:
			relativeComp = self.ownerComp if self.relativeMode else self.TDBitwigComp
			return [relativeComp.relativePath(comp) for comp in self.BitwigCompScope]
		else:
			return []

	@property
	def relativeMode(self):
		self.scanComps()
		return self.ownerComp.par.Selectrelativetothiscomp

	@property
	def relativeComp(self):
		return self.ownerComp if self.relativeMode else self.TDBitwigComp

	def onSelectedCompChange(self, path):
		self.SelectedComp = self.relativeComp.parent().op(path)
		self.handleSelectedPath(path)

	def handleSelectedPath(self, path):
		if self.SelectedComp:
			if self.TDBitwigComp:
				if self.relativeMode:
					stringPath = f"parent(2).op('{path}/out1')"
				else:
					stringPath = f"op.BitwigMain.parent().op('{path}/out1')"
				self.writeSelectChopPar(stringPath)
		else:
			self.writeSelectChopPar("")

	def writeSelectChopPar(self, expression):
		selectPar = self.selectCompCHOP.par.chops
		selectPar.expr = expression

	def checkParentShortcut(self, comp):
		if comp.parent():
			parentComp = comp.parent()
			parentShortcut = parentComp.par.parentshortcut
			if parentShortcut.eval() != '':
				return parentShortcut.eval()
			else:
				return None

	def OnNotificationReceived(self, info):
		type = info['notificationType']
		if type == 'BitwigCompChange':
			self.scanComps()
			self.ownerComp.cook(force = True)
		return

	def onParValueChange(self, par, prev):

		name = par.name
		val = par.eval()

		if name == 'Selectedcomp':
			self.onSelectedCompChange(val)
			self.ownerComp.cook(force = True)
		elif name == 'Bitwigcomptype':
			self.scanComps()
		elif name == 'Tdbitwigcomp':
			if val == None:
				self.selectCompCHOP.par.chops.val = ''
			else:
				self.scanComps()
				self.onSelectedCompChange(self.ownerComp.par.Selectedcomp.val)
		pass

	def onParPulse(self, par):
		name = par.name

		if name == 'Scan':
			self.scanComps()
		elif name == 'Openselectedcomppars':
			if self.SelectedComp:
				self.SelectedComp.openParameters()
		pass
